const item = $input.first().json;

// Use transformed GBIF fields
const has_gbif_key = !!item.speciesKey || !!item.gbif_id;
const gbif_conf = Number(item.gbif_confidence ?? item.confidence ?? 99) / 100;
const agent_conf = Number(item.confidence_score ?? item.prominence_priority ?? 0.7);

// Trust the upstream gbif_success, but add safety
const is_nomatch = item.gbif_status?.toUpperCase().includes('NOMATCH') || 
                   item.gbif_match_type === 'NONE';
const validation_complete = item.gbif_success && has_gbif_key && !is_nomatch;

const classical_mentions = Number(item.classical_mentions ?? 1);
const validation_score = Math.min(1.0, 
  (classical_mentions / 10 * 0.4) +     
  (gbif_conf * 0.4) +                   
  (agent_conf * 0.2)                    
);

return [{
  json: {
    ...item,
    prominence_score: validation_score.toFixed(4),
    gbif_confidence: gbif_conf,
    validation_complete,
    gbif_status: item.gbif_status || 'UNKNOWN'
  }
}];

// n8n v2+: Agent 1 Parse Node - GBIF Herb Resolver (returns ARRAY, preserves ALL)
try {
  const item = $input.item.json;
  let raw = item.output || item.text || item.content || item.message || item.choices?.[0]?.message?.content;

  if (!raw) {
    console.log("No raw content found");
    return [{ 
      json: { 
        skipped: true, 
        reason: "No output/text/content in agent response",
        input_herb_id: item.herb_id || 'unknown',
        classification: 'unknown'
      } 
    }];
  }

  console.log("Raw agent output:", raw.substring(0, 200));

  // Parse JSON (string/object) - handles ```json wrappers
  let herbData;
  if (typeof raw === 'string') {
    const cleaned = raw.replace(/```json|```/g, '').trim();
    herbData = JSON.parse(cleaned);
  } else {
    herbData = raw;
  }

  const herbsArray = Array.isArray(herbData) ? herbData : [herbData];

  // ALWAYS map ALL herbs, preserve input_herb_id, flag singles
  const validHerbs = herbsArray.map(h => ({
    herb_id: h.herb_id || item.herb_id,  // Preserve e.g. 729
    classification: h.classification || 'unknown',
    validated_botanical: h.validated_botanical || '',
    gbif_search_term: h.classification === 'single' ? (h.validated_botanical || h.gbif_search_term || h.herb || 'Unknown') : '',
    confidence: Number(h.confidence || 0),
    source: h.source || 'llm',
    rawAgent: h,  // Debug
    is_single_herb: h.classification === 'single' && (h.confidence ?? 0) >= 0.5
  }));

  console.log(`Mapped ${validHerbs.length} herbs, singles: ${validHerbs.filter(h => h.is_single_herb).length}`);

  // Branch 1: Any singles? → GBIF path (filter to singles only)
  if (validHerbs.some(h => h.is_single_herb)) {
    return validHerbs
      .filter(h => h.is_single_herb)
      .map(h => ({ json: h }));
  }

  // Branch 2: All non-singles → Non-herb path WITH full data
  return validHerbs.map(h => ({ 
    json: { 
      ...h, 
      skipped: true,
      reason: `Classification: ${h.classification} (conf: ${h.confidence})`
    } 
  }));

} catch (e) {
  console.error("Parse error:", e.message);
  return [{ 
    json: { 
      skipped: true, 
      reason: `Parse failed: ${e.message}`,
      input_herb_id: $input.item.json.herb_id || 'unknown',
      classification: 'parse_error'
    } 
  }];
}

console.log('GBIF Input:', $input.item.json);
// Especially: gbif_search_term, validated_botanical
return $input.all();

const item = $input.first().json;

const has_key = !!item.usageKey;
const is_plant = item.kingdom === 'Plantae';
const good_status = ['ACCEPTED', 'SYNONYM'].includes(item.status);
const good_match = ['EXACT', 'FUZZY'].includes(item.matchType);
const good_conf = Number(item.confidence ?? 0) >= 90;

const gbif_success = has_key && is_plant && good_status && good_match && !!item.family;

return [{
  json: {
    ...item,
    gbif_id: item.usageKey ?? null,
    gbif_scientific_name: item.scientificName ?? null,
    gbif_canonical_name: item.canonicalName ?? null,
    gbif_family: item.family ?? null,
    gbif_genus: item.genus ?? null,
    gbif_species: item.species ?? null,
    gbif_confidence: Number(item.confidence ?? 0),
    gbif_match_type: item.matchType ?? null,
    gbif_status: item.status ?? null,
    gbif_success
  }
}];
